<script setup lang="ts">
import { nextTick,ref } from 'vue';import { useRouter } from 'vue-router';import TripRequestForm from '@/components/trips/TripRequestForm.vue';import { useTripStore } from '@/stores/trips';import type { CreateTripInput } from '@/api/types';import { ApiError } from '@/api/client';import { requestKey } from '@/utils/id'
const busy=ref(false),error=ref(''),fieldErrors=ref<Record<string,string>>({}),store=useTripStore(),router=useRouter();let pendingKey='',pendingFingerprint=''
async function submit(value:CreateTripInput){const fingerprint=JSON.stringify(value);if(fingerprint!==pendingFingerprint){pendingKey=requestKey();pendingFingerprint=fingerprint}busy.value=true;error.value='';fieldErrors.value={};try{const trip=await store.create(value,pendingKey);pendingKey='';pendingFingerprint='';await router.push(`/trips/${trip.id}`)}catch(e){error.value=e instanceof Error?e.message:'创建失败';if(e instanceof ApiError){fieldErrors.value=Object.fromEntries((e.details??[]).filter(x=>x.field&&x.reason).map(x=>[fieldKey(x.field!),x.reason!]));const first=Object.keys(fieldErrors.value)[0];if(first)await nextTick(()=>(document.getElementById(first) as HTMLElement|null)?.focus());if(e.status!==0){pendingKey='';pendingFingerprint=''}}}finally{busy.value=false}}
function fieldKey(value:string){const root=value.replace(/^.*\.(?=(destination|startDate|days|budget|travelers|preferences|timezone|additionalRequirements))/, '').split(/[.[]/)[0]??value;return root==='budget'?'budget':root}
</script>
<template><section class="page"><p class="eyebrow">NEW JOURNEY</p><h1 tabindex="-1">规划一段新旅程</h1><p class="lead">告诉我们边界条件，AI 会把它们整理成每天都能执行的计划。</p><p v-if="error" class="banner error" role="alert">{{error}}</p><div class="panel"><TripRequestForm :busy="busy" :field-errors="fieldErrors" @submit="submit" /></div></section></template>
